void predict(float features[], float probs[3]) {
    float logits[3] = {0};
    float temp_x1[3];
    feature_x1(features[0], temp_x1);
    for (int i = 0; i < 3; i++) logits[i] += temp_x1[i];
    float temp_x2[3];
    feature_x2(features[1], temp_x2);
    for (int i = 0; i < 3; i++) logits[i] += temp_x2[i];
    logits[0] += 0.26358461f;
    logits[1] += 0.02849570f;
    logits[2] += -0.24064910f;
    // Softmax
    float max_logit = logits[0];
    for (int i = 1; i < 3; i++) if (logits[i] > max_logit) max_logit = logits[i];
    float sum_exp = 0.0f;
    for (int i = 0; i < 3; i++) {
        probs[i] = expf(logits[i] - max_logit);
        sum_exp += probs[i];
    }
    for (int i = 0; i < 3; i++) probs[i] /= sum_exp;
}

